from fastapi import FastAPI
from fastapi.responses import JSONResponse

app = FastAPI()

@app.get("/approvals/{approval_id}")
async def get_approval(approval_id: str):
    a = _pending.get(approval_id)
    if not a:
        return JSONResponse({"error": "not found"}, status_code=404)
    return JSONResponse({
        "approval_id": a.approval_id,
        "tool_name":   a.tool_name,
        "tool_input":  a.tool_input,
        "risk_tier":   a.risk_tier,
        "status":      "pending" if a.decision is None else a.decision,
    })

@app.post("/approvals/{approval_id}/approve")
async def approve(approval_id: str):
    a = _pending.get(approval_id)
    if not a or a.decision is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    a.decision = ReviewDecision.APPROVE
    a.event.set()
    return JSONResponse({"status": "approved"})

@app.post("/approvals/{approval_id}/deny")
async def deny(approval_id: str, reason: str = ""):
    a = _pending.get(approval_id)
    if not a or a.decision is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    a.decision  = ReviewDecision.DENY
    a.deny_reason = reason
    a.event.set()
    return JSONResponse({"status": "denied"})

@dataclass
class TwoPersonApproval:
    approval_id: str
    tool_name:   str
    tool_input:  dict
    approvals:   list[str] = field(default_factory=list)   # reviewer IDs who approved
    denials:     list[str] = field(default_factory=list)
    required:    int = 2

    @property
    def approved(self) -> bool:
        return len(self.approvals) >= self.required

    @property
    def denied(self) -> bool:
        return len(self.denials) >= 1   # one denial is enough to block

_two_person: dict[str, TwoPersonApproval] = {}

async def submit_two_person_vote(
    approval_id: str,
    reviewer_id: str,
    decision: ReviewDecision,
) -> dict:
    rec = _two_person.get(approval_id)
    if not rec:
        return {"error": "not found"}
    if decision == ReviewDecision.APPROVE:
        if reviewer_id not in rec.approvals:
            rec.approvals.append(reviewer_id)
    else:
        rec.denials.append(reviewer_id)
    return {
        "approved": rec.approved,
        "denied":   rec.denied,
        "votes":    {"approvals": rec.approvals, "denials": rec.denials},
    }

async def wait_for_two_person(rec: TwoPersonApproval, timeout: float = 600) -> ReviewDecision:
    """Poll until approved (2 votes) or denied (1 vote) or timeout."""
    import asyncio
    deadline = asyncio.get_event_loop().time() + timeout
    while asyncio.get_event_loop().time() < deadline:
        if rec.denied:
            return ReviewDecision.DENY
        if rec.approved:
            return ReviewDecision.APPROVE
        await asyncio.sleep(2)
    return ReviewDecision.DENY   # deny on timeout
